INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a2b10900-0000-4000-8000-000000000000','a2b00000-0000-4000-8000-000000000000','確認テスト ─ 組織設計の基本','quiz',NULL,NULL,NULL,3,2),
  ('a2b20900-0000-4000-8000-000000000000','a2b00000-0000-4000-8000-000000000000','確認テスト ─ MBO/OKR','quiz',NULL,NULL,NULL,3,4),
  ('a2b30900-0000-4000-8000-000000000000','a2b00000-0000-4000-8000-000000000000','確認テスト ─ 心理的安全性をチーム文化に組み込む','quiz',NULL,NULL,NULL,3,6),
  ('a2b40900-0000-4000-8000-000000000000','a2b00000-0000-4000-8000-000000000000','確認テスト ─ 部門間の調整','quiz',NULL,NULL,NULL,3,8),
